// // This module controls the power gating of a component based on the enable and power state signals.
// It sets the gated_power output to high when the enable signal is low and the power state signal is high,
// otherwise it sets the gated_power output to low.
module power_gating_control(  
    input wire en,  
    input wire ps,  
    output wire gated_power  
);  
    assign gated_power = en & ~ps;  
endmodule

